import React, { useState } from 'react';
import { format } from 'date-fns';
import toast from 'react-hot-toast';
import AppLayout from '../components/shared/AppLayout';
import { useAuth } from '../context/AuthContext';
import api from '../utils/api';

const plans = [
  {
    id: 'monthly',
    name: 'Monthly Impact',
    price: 'Rs 999',
    period: '/month',
    description: 'Flexible support with full access to score tracking, charity contribution, and reward draws.',
    features: [
      'Choose and support your charity',
      'Track up to 5 recent scores',
      'Enter reward draws automatically',
      'Monitor winnings and payout status',
    ],
    highlight: false,
  },
  {
    id: 'yearly',
    name: 'Yearly Impact',
    price: 'Rs 8,999',
    period: '/year',
    description: 'A stronger long-term commitment with better value and uninterrupted charitable support.',
    features: [
      'Everything in Monthly Impact',
      'Best annual value',
      'Continuous charity support across the year',
      'Priority presence in your impact journey',
    ],
    highlight: true,
    badge: 'Most persuasive value',
  },
];

const persuasionPoints = [
  'Your subscription activates the full charity-first flow immediately.',
  'Contribution preferences remain visible in your dashboard at all times.',
  'Rewards, verification, and payout tracking stay transparent from start to finish.',
];

export default function SubscriptionPage() {
  const { user, refreshUser } = useAuth();
  const [loading, setLoading] = useState(null);

  const handleSubscribe = async (plan) => {
    setLoading(plan);
    try {
      await api.post('/users/subscribe', { plan });
      await refreshUser();
      toast.success(`Welcome to the ${plan} plan`);
    } catch (err) {
      toast.error(err.response?.data?.message || 'Subscription failed');
    } finally {
      setLoading(null);
    }
  };

  const handleCancel = async () => {
    if (!window.confirm('Are you sure you want to cancel your subscription?')) return;
    setLoading('cancel');
    try {
      await api.post('/users/cancel-subscription');
      await refreshUser();
      toast.success('Subscription cancelled');
    } catch {
      toast.error('Failed to cancel subscription');
    } finally {
      setLoading(null);
    }
  };

  const isActive = user?.subscription_status === 'active';

  return (
    <AppLayout>
      <div className="max-w-6xl mx-auto space-y-8 animate-slide-up">
        <div className="grid grid-cols-1 lg:grid-cols-[1.1fr_0.9fr] gap-6 items-start">
          <div>
            <div className="section-kicker mb-4">Subscribe flow</div>
            <h1 className="page-title !text-5xl">Choose the plan that keeps impact visible and action immediate.</h1>
            <p className="text-charcoal-300 text-lg mt-4 max-w-2xl leading-relaxed">
              This flow is designed to be prominent and persuasive: subscribe, activate your dashboard, support a charity, and track every step from score to payout.
            </p>
          </div>

          <div className="story-panel p-6">
            <div className="text-xs uppercase tracking-[0.22em] text-charcoal-500 mb-4">Why subscribe now</div>
            <div className="space-y-3">
              {persuasionPoints.map((point, index) => (
                <div key={point} className="rounded-2xl border border-charcoal-800/70 bg-charcoal-950/40 px-4 py-4 animate-slide-in" style={{ animationDelay: `${index * 90}ms` }}>
                  <div className="text-sm text-charcoal-200">{point}</div>
                </div>
              ))}
            </div>
          </div>
        </div>

        {isActive && (
          <div className="story-panel p-6 border border-forest-800/40 bg-forest-900/10">
            <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
              <div>
                <span className="badge-active">
                  <span className="w-2 h-2 rounded-full bg-forest-500 animate-pulse-slow" />
                  Active subscription
                </span>
                <h3 className="font-display font-bold text-white text-2xl mt-3 capitalize">{user.plan} plan</h3>
                {user.subscription_end && (
                  <p className="text-sm text-charcoal-400 mt-1">
                    Renewal date: {format(new Date(user.subscription_end), 'MMMM d, yyyy')}
                  </p>
                )}
              </div>
              <button onClick={handleCancel} disabled={loading === 'cancel'} className="btn-danger">
                {loading === 'cancel' ? 'Cancelling...' : 'Cancel Subscription'}
              </button>
            </div>
          </div>
        )}

        <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
          {plans.map((plan, index) => {
            const isCurrent = isActive && user.plan === plan.id;

            return (
              <div
                key={plan.id}
                className={`relative story-panel p-8 transition-all duration-300 animate-slide-up ${
                  plan.highlight
                    ? 'border-gold-700/60 bg-gradient-to-b from-gold-900/20 via-charcoal-900/70 to-charcoal-950/85 shadow-[0_24px_80px_rgba(122,95,9,0.18)]'
                    : 'border-charcoal-800/90 bg-charcoal-900/55'
                } ${isCurrent ? 'ring-2 ring-forest-600' : ''}`}
                style={{ animationDelay: `${index * 120}ms` }}
              >
                {plan.badge && (
                  <div className="absolute -top-3 left-8">
                    <span className="badge-gold">{plan.badge}</span>
                  </div>
                )}
                {isCurrent && (
                  <div className="absolute -top-3 right-8">
                    <span className="badge-active">Current Plan</span>
                  </div>
                )}

                <div className="mb-6">
                  <div className="text-xs uppercase tracking-[0.2em] text-charcoal-500 mb-3">Plan choice</div>
                  <h3 className="font-display text-3xl font-bold text-white mb-2">{plan.name}</h3>
                  <p className="text-charcoal-400">{plan.description}</p>
                </div>

                <div className="flex items-end gap-2 mb-6">
                  <span className="font-display text-5xl font-bold text-white">{plan.price}</span>
                  <span className="text-charcoal-400 text-sm mb-2">{plan.period}</span>
                </div>

                <ul className="space-y-3 mb-8">
                  {plan.features.map((feature) => (
                    <li key={feature} className="flex items-start gap-3 text-sm text-charcoal-300">
                      <span className="mt-1 h-2.5 w-2.5 rounded-full bg-forest-400 shadow-[0_0_16px_rgba(98,162,98,0.45)]" />
                      <span>{feature}</span>
                    </li>
                  ))}
                </ul>

                <button
                  onClick={() => handleSubscribe(plan.id)}
                  disabled={!!loading || isCurrent}
                  className={`w-full ${plan.highlight ? 'btn-gold' : 'btn-primary'} ${isCurrent ? 'opacity-60 cursor-not-allowed' : ''}`}
                >
                  {loading === plan.id
                    ? 'Processing...'
                    : isCurrent
                    ? 'Current Plan'
                    : isActive
                    ? `Switch to ${plan.name}`
                    : `Subscribe to ${plan.name}`}
                </button>
              </div>
            );
          })}
        </div>

        <div className="story-panel p-5 text-center">
          <p className="text-sm text-charcoal-400">
            This is still a simulated payment flow, but the interface is now structured to behave like a clear subscription conversion experience.
          </p>
        </div>
      </div>
    </AppLayout>
  );
}
